{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 smoke 테스트가 통과할 경우 금요일 15:00 KST로 한다.",
        "conditions": ["smoke 테스트 통과"],
        "rejected_or_superseded_context": "수요일 릴리스 제안은 최종 결정이 아니라 내부 stretch goal로만 남았다."
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다.",
        "conditions": ["packageName mismatch 발생"],
        "rejected_or_superseded_context": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경하자는 제안은 거절되었다. contract 자체가 잘못된 경우에만 script 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs를 변경해 packageName mismatch를 무시한다.",
        "proposed_by": "Hara",
        "outcome": "rejected",
        "reason": "최종 결정은 mismatch 발생 시 package config를 먼저 확인하는 것이다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "internal stretch goal only",
        "note": "Doyun이 smoke 테스트 선통과 필요성을 들어 반대했으며, 최종 공개 릴리스 목표가 아니다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README install steps 검토",
        "status": "검토 필요성이 언급되었으나 owner가 지정되지 않았다.",
        "suggested_timing": "목요일까지 가능하면 검토"
      },
      {
        "topic": "최종 릴리스 승인 권한",
        "status": "결정되지 않았다."
      },
      {
        "topic": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부",
        "status": "결정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있다.",
        "category": "release readiness"
      },
      {
        "risk": "README install steps가 오래된 상태이면 release notes가 사용자를 오도할 수 있다.",
        "category": "documentation accuracy"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한은 누구에게 있는가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed from fixture"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed from fixture"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "confirmed, no exact deadline set",
      "source_certainty": "confirmed from fixture"
    },
    {
      "owner": null,
      "task": "README install steps를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "mentioned, owner unassigned",
      "source_certainty": "mentioned but not assigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST smoke 테스트 결과 공유 여부",
      "Doyun의 금요일 12:00 KST action_items.md failure triage note 작성 여부",
      "smoke 결과 이후 Hara의 generated tarball path 확인 결과",
      "README install steps 검토 owner 지정 여부",
      "최종 릴리스 승인 권한자 확정 여부",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 owner",
      "정해지지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "customer": "회의 기록에 고객 또는 외부 파트너가 명시되지 않았으므로 생성하지 않는다.",
    "budget": "예산 관련 언급이 없으므로 생성하지 않는다.",
    "security": "보안 사고 언급이 없으므로 생성하지 않는다.",
    "outage": "프로덕션 장애 언급이 없으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항 언급이 없으므로 생성하지 않는다.",
    "owner": "명시적으로 배정된 owner만 action item owner로 기록한다.",
    "deadline": "명시된 due만 기록하고, Hara의 작업처럼 정확한 deadline이 없는 경우 null로 둔다.",
    "release_conditions": "공개 릴리스 목표는 smoke 테스트 통과 조건부이며, 수요일은 내부 stretch goal로만 기록한다."
  }
}
